1	const PROCESSING_FEE = 5;
2	
3	const MAIN_ITEM_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	};
9	
10	const COMPONENT_PREMIUM = 25;
11	const COMPONENT_BLOCK_PREMIUM = 60;
12	const COMPONENT_BLOCK_SIZE = 3;
13	
14	const isComponent = (type: string): boolean => !MAIN_ITEM_PREMIUMS.hasOwnProperty(type);
15	
16	const CURSED_SURCHARGE_RATE = 0.5;
17	const HIGH_ENCHANTMENT_THRESHOLD = 5;
18	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
19	
20	const calculateItemSurcharges = (item: { type: string; cursed?: boolean; enchantment?: number }): number => {
21	  const base = MAIN_ITEM_PREMIUMS[item.type] ?? 0;
22	  let surcharges = 0;
23	  if (item.cursed) {
24	    surcharges += base * CURSED_SURCHARGE_RATE;
25	  }
26	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
27	    surcharges += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
28	  }
29	  return surcharges;
30	};
31	
32	const calculateComponentGroupPremium = (count: number): number =>
33	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
34	
35	const FIRST_INSURANCE_RATE = 0.1;
36	const LOYALTY_DISCOUNT_RATE = 0.2;
37	const LOYALTY_THRESHOLD_YEARS = 2;
38	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
39	
40	const calculatePremium = (items: { type: string; cursed?: boolean; enchantment?: number }[], yearsWithMHPCO: number, isFollowUp: boolean): number => {
41	  let policyBasePremium = 0;
42	  let itemSurcharges = 0;
43	
44	  const componentCounts: Record<string, number> = {};
45	  for (const item of items) {
46	    if (isComponent(item.type)) {
47	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
48	    } else {
49	      policyBasePremium += MAIN_ITEM_PREMIUMS[item.type] ?? 0;
50	      itemSurcharges += calculateItemSurcharges(item);
51	    }
52	  }
53	
54	  for (const count of Object.values(componentCounts)) {
55	    policyBasePremium += calculateComponentGroupPremium(count);
56	  }
57	
58	  let policyModifiers = policyBasePremium * FIRST_INSURANCE_RATE;
59	  if (yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS) {
60	    policyModifiers -= policyBasePremium * LOYALTY_DISCOUNT_RATE;
61	  }
62	  if (isFollowUp) {
63	    policyModifiers -= policyBasePremium * FOLLOW_UP_DISCOUNT_RATE;
64	  }
65	
66	  return Math.ceil(policyBasePremium + itemSurcharges + policyModifiers + PROCESSING_FEE);
67	};
68	
69	export function processScenario(scenario: { customer: { yearsWithMHPCO: number }; steps: { op: string; items?: { type: string }[] }[] }): { results: unknown[] } {
70	  let quoteCount = 0;
71	  const results = scenario.steps.map((step) => {
72	    const isFollowUp = quoteCount > 0;
73	    quoteCount++;
74	    const premium = calculatePremium(step.items ?? [], scenario.customer.yearsWithMHPCO, isFollowUp);
75	    return { premium };
76	  });
77	  return { results };
78	}
